import {
  ElapsedTimer,
  GameRunningState,
  useElapsedTime,
} from '@kyokuya/react-game-core'
import type { CellClickHandler, CellInputHandler } from '@kyokuya/react-sudoku'
import ReactSudoku from '@kyokuya/react-sudoku'
import {
  Button,
  Dialog,
  DialogActions,
  DialogContent,
  IconButton,
  MenuItem,
  Modal,
  Select,
  Slider,
  Tooltip,
} from '@material-ui/core'
import HintIcon from '@material-ui/icons/EmojiObjects'
import GameRunningIcon from '@material-ui/icons/Pause'
import GamePausedIcon from '@material-ui/icons/PauseCircleFilled'
import GamePendingIcon from '@material-ui/icons/PlayArrow'
import RefreshIcon from '@material-ui/icons/Refresh'
import TimerIcon from '@material-ui/icons/Timer'
import VisibilityIcon from '@material-ui/icons/Visibility'
import cn from 'clsx'
import React, { useCallback, useEffect, useMemo, useRef, useState } from 'react'
import SudokuInputComponent from './InputComponent'
import './style.styl'

export const SudokuGame: React.FC = () => {
  const containerRef = useRef<HTMLDivElement>(null)
  const [childMatrixSize, setChildMatrixSize] = useState<number>(3)
  const [digitalBase, setDigitalBase] = useState<number>(10)
  const [difficulty, setDifficulty] = useState<number>(20)
  const [score, setScore] = useState<number>(0)
  const [gameTick, setGameTick] = useState<number>(0)
  const [hintTick, setHintTick] = useState<number>(0)
  const [inputDialogVisible, setInputDialogVisible] = useState<boolean>(false)
  const [solutionVisible, setSolutionVisible] = useState<boolean>(false)
  const [restartDialogVisible, setRestartDialogVisible] =
    useState<boolean>(false)
  const [gameState, setGameState] = useState<GameRunningState>(
    GameRunningState.PENDING,
  )

  const sudokuInputRef = useRef<CellInputHandler>(null)
  const sudokuValueRef = useRef<string>('')

  // Restart game.
  const handleGameRestart = useCallback(() => {
    setRestartDialogVisible(false)
    setGameState(GameRunningState.PENDING)
    setGameTick(v => v + 1)
  }, [])

  const handleInput = useCallback(
    (text: string) => {
      setInputDialogVisible(false)
      if (sudokuInputRef.current == null) return

      const value = /^\s*$/.test(text) ? 0 : Number.parseInt(text, digitalBase)
      if (Number.isInteger(value)) {
        sudokuInputRef.current(value - 1)
      }
    },
    [digitalBase],
  )

  const handleChangeableCellClicked = useCallback<CellClickHandler>(
    ({ v }) => {
      if (gameState === GameRunningState.RUNNING) {
        sudokuValueRef.current =
          v === undefined || v === -1 ? '' : (v + 1).toString(digitalBase)
        setInputDialogVisible(true)
      }
    },
    [digitalBase, gameState],
  )

  // When the game restarts, clear the hint
  useEffect(
    () => setHintTick(0),
    [difficulty, gameTick, childMatrixSize, digitalBase],
  )

  // Calc the score
  const usedTime: number = useElapsedTime(gameState)
  useEffect(() => {
    if (gameState === GameRunningState.FINISHED) {
      const totalTime: number = childMatrixSize ** 4 * 1000
      if (usedTime >= totalTime) return

      const totalScore: number = (childMatrixSize ** 4 * difficulty) / 100
      const gotScore: number = ((totalTime - usedTime) * totalScore) / 1000
      setScore(v => v + Math.round(gotScore))
    }
  }, [childMatrixSize, gameState, usedTime, difficulty])

  const overlay = useMemo<React.ReactNode>(() => {
    switch (gameState) {
      case GameRunningState.PENDING: {
        return (
          <div className="game-sudoku__overlay">
            <Button
              className="game-sudoku__start-button"
              variant="contained"
              color="primary"
              startIcon={<GamePendingIcon />}
              onClick={() => setGameState(GameRunningState.RUNNING)}
            >
              Start
            </Button>
          </div>
        )
      }
      case GameRunningState.PAUSED: {
        return (
          <div className="game-sudoku__overlay">
            <Button
              variant="contained"
              color="primary"
              startIcon={<GamePausedIcon />}
              onClick={() => setGameState(GameRunningState.RUNNING)}
            >
              Resume
            </Button>
          </div>
        )
      }
      case GameRunningState.FINISHED: {
        return (
          <div className="game-sudoku__overlay">
            <p className="game-sudoku__finished-banner">đźŽ‰ You win!</p>
          </div>
        )
      }
      default:
        return null
    }
  }, [gameState])

  return (
    <div
      ref={containerRef}
      className={cn('game-sudoku', {
        'game-sudoku--4x4': childMatrixSize === 2,
        'game-sudoku--9x9': childMatrixSize === 3,
        'game-sudoku--16x16': childMatrixSize === 4,
        'game-sudoku--finished': gameState === GameRunningState.FINISHED,
      })}
    >
      <div className="game-sudoku__wrapper">
        <div className="game-sudoku-toolbar">
          <div className="game-sudoku-toolbar-item">
            <span>Size:</span>
            <Select
              value={childMatrixSize}
              disabled={gameState !== GameRunningState.PENDING}
              onChange={e => setChildMatrixSize(Number(e.target.value))}
            >
              <MenuItem value={2}>4x4</MenuItem>
              <MenuItem value={3}>9x9</MenuItem>
              <MenuItem value={4}>16x16</MenuItem>
            </Select>
          </div>
          <div className="game-sudoku-toolbar-item">
            <span>Radix:</span>
            <Select
              value={digitalBase}
              disabled={gameState !== GameRunningState.PENDING}
              onChange={e => setDigitalBase(Number(e.target.value))}
            >
              <MenuItem value={10}>Decimal (x10)</MenuItem>
              <MenuItem value={16}>Hexadecimal (x16)</MenuItem>
            </Select>
          </div>
          <div className="game-sudoku-toolbar-item game-sudoku-toolbar-item__difficulty">
            <span>Difficulty:</span>
            <Slider
              value={difficulty}
              disabled={gameState !== GameRunningState.PENDING}
              step={1}
              min={0}
              max={100}
              valueLabelDisplay="auto"
              aria-labelledby="sudoku-difficulty"
              onChange={(e, v) => setDifficulty(v as number)}
            />
          </div>
          <div className="game-sudoku-toolbar-item game-sudoku-toolbar-item__buttons">
            <Button
              variant="contained"
              color="default"
              startIcon={<RefreshIcon />}
              onClick={() => setRestartDialogVisible(true)}
            >
              Restart
            </Button>
            <Button
              variant="contained"
              color="default"
              disabled={gameState !== GameRunningState.RUNNING}
              startIcon={<HintIcon />}
              onClick={() => setHintTick(v => v + 1)}
            >
              HINT
            </Button>
            <Button
              variant="contained"
              color="secondary"
              disabled={gameState !== GameRunningState.RUNNING}
              startIcon={<VisibilityIcon />}
              onClick={() => setSolutionVisible(true)}
            >
              Cheat
            </Button>
          </div>
          <div className="game-sudoku-toolbar-item game-sudoku-toolbar-item__state">
            <div
              key="state-buttons"
              className="game-sudoku-toolbar__state-buttons"
            >
              {gameState === GameRunningState.RUNNING && (
                <Tooltip title="Pause">
                  <IconButton
                    color="primary"
                    onClick={() => setGameState(GameRunningState.PAUSED)}
                  >
                    <GameRunningIcon />
                  </IconButton>
                </Tooltip>
              )}
            </div>
            <div
              key="elapsed-time"
              className="game-sudoku-toolbar__elapsed-time"
            >
              <Tooltip title="Time used">
                <TimerIcon />
              </Tooltip>
              &nbsp;&nbsp;
              <ElapsedTimer gameState={gameState} />
            </div>
            <div key="score" className="game-sudoku-toolbar__score">
              Score: {score}
            </div>
          </div>
        </div>
        <div className="game-sudoku-main">
          <ReactSudoku
            inputRef={sudokuInputRef as any}
            childMatrixSize={childMatrixSize}
            difficulty={difficulty / 100.0}
            gameState={gameState}
            gameTick={gameTick}
            hintTick={hintTick}
            digitalBase={digitalBase}
            onChangeableCellClicked={handleChangeableCellClicked}
            onGameStateChanged={v => {
              if (v) {
                if (gameState === GameRunningState.RUNNING) {
                  setGameState(GameRunningState.FINISHED)
                }
              } else {
                if (gameState === GameRunningState.FINISHED) {
                  setGameState(GameRunningState.RUNNING)
                }
              }
            }}
            overlay={overlay}
            renderSolutionBoard={node => (
              <Modal
                open={solutionVisible}
                container={containerRef.current}
                keepMounted={true}
                disableAutoFocus={true}
                BackdropProps={{ timeout: 500 }}
                closeAfterTransition={true}
                onClose={() => setSolutionVisible(false)}
              >
                <div
                  className="game-sudoku__solution-wrapper"
                  onClick={() => setSolutionVisible(false)}
                >
                  <span className="game-sudoku__solution-close">&times;</span>
                  <div onClick={e => e.stopPropagation()}>{node}</div>
                </div>
              </Modal>
            )}
          />
        </div>
      </div>
      <SudokuInputComponent
        container={containerRef.current}
        initialValue={sudokuValueRef.current}
        visible={inputDialogVisible}
        digitalBase={digitalBase}
        label={`A ${digitalBase === 10 ? 'decimal' : 'hexadecimal'} number`}
        onCancel={() => setInputDialogVisible(false)}
        onConfirm={handleInput}
      />
      <Dialog
        container={containerRef.current}
        open={restartDialogVisible}
        onClose={() => setRestartDialogVisible(false)}
        aria-labelledby="confirm-to-restart"
      >
        <DialogContent>Are you sure you want to start over?</DialogContent>
        <DialogActions>
          <Button
            color="default"
            onClick={() => setRestartDialogVisible(false)}
          >
            Cancel
          </Button>
          <Button color="primary" onClick={handleGameRestart}>
            Confirm
          </Button>
        </DialogActions>
      </Dialog>
    </div>
  )
}

export default SudokuGame
